  1→import { RichTextPlugin } from "@lexical/react/LexicalRichTextPlugin";
  2→import { ContentEditable } from "@lexical/react/LexicalContentEditable";
  3→import ImageNode from "../Editor/nodes/ImageNode";
  4→import MentionNode from "../Editor/nodes/MentionNode";
  5→import { HeadingNode, QuoteNode } from "@lexical/rich-text";
  6→import { LexicalComposer } from "@lexical/react/LexicalComposer";
  7→import { LexicalErrorBoundary } from "@lexical/react/LexicalErrorBoundary";
  8→import { useLocation, useNavigate, useParams } from "react-router-dom";
  9→import './contentviewer.css'
 10→import { useEffect, useMemo, useRef, useState } from "react";
 11→import { AnimatePresence, motion } from "framer-motion";
 12→import { MoonLoader } from "react-spinners";
 13→import CalculateText from "../postCards/calculateReadingTime";
 14→import ParseContent from "../postCards/parseData";
 15→import { useBookMarkMutation, useFollowMutation, useAddViewsMutation, useReactionMutation } from "../../../utils/useMutation";
